const body = $input.first().json.body ?? $input.first().json;
const score = body.confluenceScore ?? 50;
return [{
  json: {
    master: {
      summary: `WDO: mini dólar com confluence ${score}/100. Correlação macro e fluxo cambial.`,
      strengths: body.positive ?? [],
      weaknesses: body.negative ?? [],
      probability: score >= 65 ? 'Elevada' : 'Moderada',
      risk: 'Eventos Fed / PTAX'
    },
    agentInsights: [
      ...(body.agentInsights ?? []),
      {
        agentId: 'wdo-specialist',
        asset: 'WDO',
        specialization: 'Mini Dólar',
        summary: `Setup WDO — ${body.recommendation ?? 'Neutro'}`,
        highlights: [`Score ${score}`, ...(body.zones ?? []).slice(0,2).map(z => z.label)]
      }
    ]
  }
}];
